INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('bleachedSandProperty', 'BleachedSand', 'http://w3id.org/glosis/model/common/bleachedSandProperty', 'Classification of bleached sand characteristics based on the percentage of surface covered. See more in Guidelines for Soil Description issued by the FAO: table 23') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('cracksDepthProperty', 'CracksDepth', 'http://w3id.org/glosis/model/common/cracksDepthProperty', 'List of suggested classes of surface cracks in shrink–swell clay-rich soils after they dry out. See more in guidelines for Soil Description issued by the FAO: table 21,2') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('cracksDistanceProperty', 'CracksDistance', 'http://w3id.org/glosis/model/common/cracksDistanceProperty', 'Classification of the surface cracks based on distance between the cracks measured in meters. See more in Guidelines for Soil Description issued by the FAO: table 21,3') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('cracksWidthProperty', 'CracksWidth', 'http://w3id.org/glosis/model/common/cracksWidthProperty', 'Classification of surface cracks based on the width. See more in Guidelines for Soil Description issued by the FAO: table 21,1') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('fragmentCoverProperty', 'FragmentCover', 'http://w3id.org/glosis/model/common/fragmentCoverProperty', 'Coarse surface fragments, including those partially exposed, should be described in terms of percentage of surface coverage and of size of the fragments. See more in Guidelines for Soil Description issued by the FAO: table 15,1') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('fragmentsSizeProperty', 'FragmentsSize ', 'http://w3id.org/glosis/model/common/fragmentsSizeProperty', 'Classes of occurrence of coarse surface fragments are correlated with the ones for rock outcrop. See more in guidelines for Soil Description issued by the FAO: table 15,2') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('organicMatterClassProperty', 'OrganicMatterClass', 'http://w3id.org/glosis/model/common/organicMatterClassProperty', 'Refers to the categorization or classification of soil based on the quality, quantity, and composition of organic matter present, influencing soil properties such as fertility, water retention, and microbial activity. Source: Source: FAO, Soil Organic Matter and Soil Health, Land and Water Development Division.') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('rockAbundanceProperty', 'RockAbundance', 'http://w3id.org/glosis/model/common/rockAbundanceProperty', 'Abundance of rock fragments and artefacts, by volume. See more in Guidelines for Soil Description issued by the FAO: table 26') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('rockShapeProperty', 'RockShape', 'http://w3id.org/glosis/model/common/rockShapeProperty', 'The general shape or roundness of rock fragments. See more on Guidelines for Soil Description issued by the FAO: table 28') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('rockSizeProperty', 'RockSize', 'http://w3id.org/glosis/model/common/rockSizeProperty', 'Classification for rock fragments and artefacts influences the nutrient status, water movement, use and management of the soil. See more in guidelines for Soil Description issued by the FAO: table 27') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('weatheringFragmentsProperty', 'WeatheringFragments', 'http://w3id.org/glosis/model/common/weatheringFragmentsProperty', 'Classification of weathering of coarse fragments. See more in Guidelines for Soil Description issued by the FAO: table 29') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('saltCoverProperty', 'SaltCover', 'http://w3id.org/glosis/model/surface/saltCoverProperty', 'The occurrence of salt at the surface may be described in terms of cover, appearance and type of salt. See more in the guidelines for Soil Description issued by the FAO: table 22,1') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('SaltThicknessProperty', 'SaltThickness', 'http://w3id.org/glosis/model/surface/saltThicknessProperty', 'The occurrence of salt at the surface may be described in terms of cover, appearance and type of salt. See more in the Guidelines for Soil Description issued by the FAO: table 22,2') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('sealingConsistenceProperty', 'SealingConsistence', 'http://w3id.org/glosis/model/surface/sealingConsistenceProperty', 'Classification of the attributes of surface sealing based on consistency. See more in Guidelines for Soil Description issued by the FAO: table 20,2') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('sealingThicknessProperty', 'SealingThickness', 'http://w3id.org/glosis/model/surface/sealingThicknessProperty', 'Surface sealing is used to describe crusts that develop at the soil surface after the topsoil dries out. See more in Guidelines for Soil Description issued by the FAO: 20,1') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('weatheringFragmentsProperty', 'WeatheringFragments', 'http://w3id.org/glosis/model/common/weatheringFragmentsProperty', 'Classification of weathering of coarse fragments. See more in Guidelines for Soil Description issued by the FAO: table 29') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('cropClassProperty', 'CropClass', 'http://w3id.org/glosis/model/siteplot/cropClassProperty', 'Examples for the most common crops with their recommended codes. See more in guidelines for Soil Description issued by the FAO: table 9') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('erosionActivityPeriodProperty', 'ErosionActivityPeriod', 'http://w3id.org/glosis/model/siteplot/erosionActivityPeriodProperty', 'The period of activity of accelerated erosion or deposition is described using the recommended classes. See more in Guidelines for Soil Description issued by the FAO: table 19') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('erosionAreaAffectedProperty', 'ErosionAreaAffected', 'http://w3id.org/glosis/model/siteplot/erosionAreaAffectedProperty', 'Classification of total area affected by erosion and deposition. See more in Guidelines for Soil Description issued by the FAO: table 17') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('erosionCategoryProperty', 'ErosionCategory', 'http://w3id.org/glosis/model/siteplot/erosionCategoryProperty', 'Erosion can be classified as water or wind erosion and include off-site effects such as deposition; a third major category is mass movements (landslides and related phenomena). See more in Guidelines for Soil Description issued by the FAO: table 16') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('erosionDegreeProperty', 'ErosionDegree', 'http://w3id.org/glosis/model/siteplot/erosionDegreeProperty', 'Classification of erosion, by degree. See more in guidelines for Soil Description issued by the FAO: table 18') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('erosionTotalAreaAffectedProperty', 'ErosionTotalAreaAffected', 'http://w3id.org/glosis/model/siteplot/erosionTotalAreaAffectedProperty', 'The total area affected by erosion and deposition is estimated following the classes defined by SOTER (FAO, 1995). See more in the Guidelines for Soil Description issued by the FAO: table 17') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('floodDurationProperty', 'FloodDuration', 'http://w3id.org/glosis/model/siteplot/floodDurationProperty', 'Related to the amount of time an area remains inundated by floodwater.  This metric is important because it helps assess the extent of waterlogging and its impact on soil properties, particularly in terms of oxygen availability and soil aeration. Flood duration affects the mobility of nutrients and contaminants within the soil, influencing both agricultural productivity and environmental quality. Longer flood durations can also lead to changes in soil texture and structure due to the continuous movement and deposition of particles during inundation​. Source: Guidance for Flood Risk Analysis and Mapping') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('floodFrequencyProperty', 'FloodFrequency', 'http://w3id.org/glosis/model/siteplot/floodFrequencyProperty', 'Refers to the statistical analysis of the occurrence of floods at a particular location over a defined time period. It often involves calculating the recurrence intervals or return periods of flood events, which are typically used to understand how often a specific flood magnitude (like a 100-year flood) is likely to occur. Source: Introduction to Flood Frequency Analysis') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('geologyProperty', 'Geology', 'http://w3id.org/glosis/model/siteplot/geologyProperty', 'In order to be able to work in smaller scales, some additional natural and anthropogenic parent materials are used for the identification of rocks  in the field, the keys to the most important rock types are provided in the hierarchical SOTER list. See more in the guidelines for Soil Description issued by the FAO: table 12') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('humanInfluenceClassProperty', 'HumanInfluenceClass', 'http://w3id.org/glosis/model/siteplot/humanInfluenceClassProperty', 'This item refers to any evidence of human activity that is likely to have affected the landscape or the physical and chemical properties of the soil. See more in the Guidelines for Soil Description issued by the FAO: table 10') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('landUseClassProperty', 'LandUseClass', 'http://w3id.org/glosis/model/siteplot/landUseClassProperty', 'Land use applies to the current use of the land, whether agricultural or nonagricultural, in which the soil is located. See more in the guidelines for Soil Description issued by the FAO: table 8') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('landformComplexProperty', 'LandformComplex', 'http://w3id.org/glosis/model/siteplot/landformComplexProperty', 'Subdivisions for complex landforms. See more in Guidelines for Soil Description issued by the FAO: table 5') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('lithologyProperty', 'Lithology', 'http://w3id.org/glosis/model/siteplot/lithologyProperty', 'In order to be able to work in smaller scales, some additional natural and anthropogenic parent materials are used for the identification of rocks  in the field, the keys to the most important rock types are provided in the hierarchical SOTER list. See more in the guidelines for Soil Description issued by the FAO: table 12') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('MajorLandFormProperty', 'MajorLandForm', 'http://w3id.org/glosis/model/siteplot/majorLandFormProperty', 'Hierarchy of major landforms. See more in Guidelines for Soil Description issued by the FAO: table 4') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('ParentDepositionProperty', 'ParentDeposition', 'http://w3id.org/glosis/model/siteplot/parentDepositionProperty', 'Erosion can be classified as water or wind erosion and include off-site effects such as deposition; a third major category is mass movements (landslides and related phenomena). See more in Guidelines for Soil Description issued by the FAO: table 16') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('parentLithologyProperty', 'ParentLithology', 'http://w3id.org/glosis/model/siteplot/parentLithologyProperty', 'In order to be able to work in smaller scales, some additional natural and anthropogenic parent materials are used for the identification of rocks  in the field, the keys to the most important rock types are provided in the hierarchical SOTER list. See more in the guidelines for Soil Description issued by the FAO: table 12') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('parentTextureUnconsolidatedProperty', 'ParentTextureUnconsolidated', 'http://w3id.org/glosis/model/siteplot/parentTextureUnconsolidatedProperty', 'Texture of a soil that is unconsolidated or loose, typically not bound into a compact mass. It describes the proportions of sand, silt, and clay in the soil, which directly influences the soil''s physical properties such as water retention, aeration, and fertility. This texture classification can impact various soil management practices, such as tillage, irrigation, and erosion control. Source: Canadian Soil Information Service - chapter 17 & Geosciences libretexts - 3.1: Soil Texture and Structure. Possible values include unconsolidated Sand,Silt, Clay, Loam. Silty Sand, Clayey Sand') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('PhysiographyProperty', 'Physiography', 'http://w3id.org/glosis/model/siteplot/physiographyProperty', 'The relative position of the site within the land should be indicated. The position affects the hydrological conditions of the site. See more in the Guidelines for Soil Description issued by the FAO: figure 2') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('rockOutcropsCoverProperty', 'RockOutcropsCover', 'http://w3id.org/glosis/model/siteplot/rockOutcropsCoverProperty', 'Recommended classes of percentage of surface cover and of average distance between rock outcrops. See more in Guidelines for Soil Description issued by the FAO: table 14,1') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('rockOutcropsDistanceProperty', 'RockOutcropsDistance', 'http://w3id.org/glosis/model/siteplot/rockOutcropsDistanceProperty', 'Recommended classes of percentage of surface cover and of average distance between rock outcrops. See more in Guidelines for Soil Description issued by the FAO: table 14,2') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('slopeFormProperty', 'SlopeForm', 'http://w3id.org/glosis/model/siteplot/slopeFormProperty', 'The slope form refers to the general shape of the slope in both the vertical and horizontal directions. See more in Guidelines for Soil Description issued by the FAO: table 6') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('slopeGradientClassProperty', 'SlopeGradientClass', 'http://w3id.org/glosis/model/siteplot/slopeGradientClassProperty', 'Slope gradient classes measured on the percentage of slope. See more in Guidelines for Soil Description issued by the FAO: table 7') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('slopePathwaysProperty', 'SlopePathways', 'http://w3id.org/glosis/model/siteplot/slopePathwaysProperty', 'The slope form refers to the general shape of the slope in both the vertical and horizontal directions. See more in guidelines for Soil Description issued by the FAO: figure 3') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('surfaceAgeProperty', 'SurfaceAge', 'http://w3id.org/glosis/model/siteplot/surfaceAgeProperty', 'The age of the landscape is important information from which the possible duration of the occurrence of soil formation processes can be derived. See more in guidelines for Soil Description issued by the FAO: table 13') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('VegetationClassProperty', 'VegetationClass', 'http://w3id.org/glosis/model/siteplot/vegetationClassProperty', 'Classification of vegetation.See more in Guidelines for Soil Description issued by the FAO: table 11') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('weatherConditionsCurrentProperty', 'WeatherCurrent', 'http://w3id.org/glosis/model/siteplot/weatherConditionsCurrentProperty', 'Codes for weather conditions.See in Guidelines for Soil Description issued by the FAO: table 2') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('weatherConditionsPastProperty', 'WeatherPast', 'http://w3id.org/glosis/model/siteplot/weatherConditionsPastProperty', 'Codes for weather conditions.See in Guidelines for Soil Description issued by the FAO: table 2') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('weatheringRockProperty', 'WeatheringRock', 'http://w3id.org/glosis/model/siteplot/weatheringRockProperty', 'Classification of weathering of coarse fragments. See more in Guidelines for Soil Description issued by the FAO: table 29') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('profileDescriptionStatusProperty', 'ProfileDescriptionStatus', 'http://w3id.org/glosis/model/profile/profileDescriptionStatusProperty', 'Soil profile description status. See more in Guidelines for Soil Description issued by the FAO: table 1') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('bleachedSandProperty', 'BleachedSand', 'http://w3id.org/glosis/model/common/bleachedSandProperty', 'Classification of bleached sand characteristics based on the percentage of surface covered. See more in Guidelines for Soil Description issued by the FAO: table 23') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('cracksDepthProperty', 'CracksDepth', 'http://w3id.org/glosis/model/common/cracksDepthProperty', 'List of suggested classes of surface cracks in shrink–swell clay-rich soils after they dry out. See more in guidelines for Soil Description issued by the FAO: table 21,2') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('cracksDistanceProperty', 'CracksDistance', 'http://w3id.org/glosis/model/common/cracksDistanceProperty', 'Classification of the surface cracks based on distance between the cracks measured in meters. See more in Guidelines for Soil Description issued by the FAO: table 21,3') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('cracksWidthProperty', 'CracksWidth', 'http://w3id.org/glosis/model/common/cracksWidthProperty', 'Classification of surface cracks based on the width. See more in Guidelines for Soil Description issued by the FAO: table 21,1') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('fragmentCoverProperty', 'FragmentCover', 'http://w3id.org/glosis/model/common/fragmentCoverProperty', 'Coarse surface fragments, including those partially exposed, should be described in terms of percentage of surface coverage and of size of the fragments. See more in Guidelines for Soil Description issued by the FAO: table 15,1') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('fragmentsSizeProperty', 'FragmentsSize ', 'http://w3id.org/glosis/model/common/fragmentsSizeProperty', 'Classes of occurrence of coarse surface fragments are correlated with the ones for rock outcrop. See more in guidelines for Soil Description issued by the FAO: table 15,2') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('organicMatterClassProperty', 'OrganicMatterClass', 'http://w3id.org/glosis/model/common/organicMatterClassProperty', 'Refers to the categorization or classification of soil based on the quality, quantity, and composition of organic matter present, influencing soil properties such as fertility, water retention, and microbial activity. Source: Source: FAO, Soil Organic Matter and Soil Health, Land and Water Development Division.') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('rockAbundanceProperty', 'RockAbundance', 'http://w3id.org/glosis/model/common/rockAbundanceProperty', 'Abundance of rock fragments and artefacts, by volume. See more in Guidelines for Soil Description issued by the FAO: table 26') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('rockShapeProperty', 'RockShape', 'http://w3id.org/glosis/model/common/rockShapeProperty', 'The general shape or roundness of rock fragments. See more on Guidelines for Soil Description issued by the FAO: table 28') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('rockSizeProperty', 'RockSize', 'http://w3id.org/glosis/model/common/rockSizeProperty', 'Classification for rock fragments and artefacts influences the nutrient status, water movement, use and management of the soil. See more in guidelines for Soil Description issued by the FAO: table 27') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('weatheringFragmentsProperty', 'WeatheringFragments', 'http://w3id.org/glosis/model/common/weatheringFragmentsProperty', 'Classification of weathering of coarse fragments. See more in Guidelines for Soil Description issued by the FAO: table 29') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('biologicalAbundanceProperty', 'BiologicalAbundance', 'http://w3id.org/glosis/model/layerhorizon/biologicalAbundanceProperty', 'Classification of the abundance of biological activity. See more in Guidelines for Soil Description issued by the FAO: table 81') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('biologicalFeaturesProperty', 'BiologicalFeatures', 'http://w3id.org/glosis/model/layerhorizon/biologicalFeaturesProperty', 'Examples of biological features. See more in Guidelines for Soil Description issued by the FAO: table 82') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('boundaryDistinctnessProperty', 'BoundaryDistinctness', 'http://w3id.org/glosis/model/layerhorizon/boundaryDistinctnessProperty', 'The distinctness of the boundary refers to the thickness of the zone in which the horizon boundary can be located without being in one of the adjacent horizons. See more in the  Guidelines for Soil Description issued by the FAO: table 24.1') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('boundaryTopographyProperty', 'BoundaryTopography', 'http://w3id.org/glosis/model/layerhorizon/boundaryTopographyProperty', 'Classification of horizon boundaries by topography. See more in Guidelines for Soil Description issued by the FAO: table 24,2') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('bulkDensityMineralProperty', 'BulkDensityMineral', 'http://w3id.org/glosis/model/layerhorizon/bulkDensityMineralProperty', 'Field determinations of bulk density may be obtained by estimating the force required to push a knife into a soil horizon exposed at a field moist pit wall. See more in Guidelines for Soil Description issued by the FAO: table 58') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('bulkDensityPeatProperty', 'BulkDensityPeat', 'http://w3id.org/glosis/model/layerhorizon/bulkDensityPeatProperty', 'Bulk density and volume of solids of organic soils can be estimated after the decomposition stage or the extent of peat drainage. See more in guidelines for Soil Description issued by the FAO: table 59,3') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('carbonatesContentProperty', 'CarbonatesContent', 'http://w3id.org/glosis/model/layerhorizon/carbonatesContentProperty', 'Classes for the reaction of carbonates in the soil matrix. See more in Guidelines for Soil Description issued by the FAO: table 38') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('carbonatesFormsProperty', 'CarbonatesForms', 'http://w3id.org/glosis/model/layerhorizon/carbonatesFormsProperty', 'The forms of secondary carbonates in soils are diverse and are considered to be informative for diagnostics of soil genesis. See more in guidelines for Soil Description issued by the FAO: table 39') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('cementationContinuityProperty', 'CementationContinuity', 'http://w3id.org/glosis/model/layerhorizon/cementationContinuityProperty', 'The occurrence of cementation or compaction in pans or otherwise is described according to its nature, continuity, structure, agent and degree. See more in the guidelines for Soil Description issued by the FAO: table 69') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('cementationDegreeProperty', 'CementationDegree', 'http://w3id.org/glosis/model/layerhorizon/cementationDegreeProperty', 'The classification of the degree of cementation/compaction. See more in Guidelines for Soil Description issued by the FAO: table 72') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('cementationFabricProperty', 'CementationFabric', 'http://w3id.org/glosis/model/layerhorizon/cementationFabricProperty', 'Classification of the fabric of the cemented/compacted layer. See more in Guidelines for Soil Description issued by the FAO: table 70') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('cementationNatureProperty', 'CementationNature', 'http://w3id.org/glosis/model/layerhorizon/cementationNatureProperty', 'Classification of the nature of cementation/compaction. See more in Guidelines for Soil Description issued by the FAO: table 71') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('coatingAbundanceProperty', 'CoatingAbundance', 'http://w3id.org/glosis/model/layerhorizon/coatingAbundanceProperty', 'Classification of abundance of coatings. See more in Guidelines for Soil Description issued by the FAO: table 64') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('coatingContrastProperty', 'CoatingContrast', 'http://w3id.org/glosis/model/layerhorizon/coatingContrastProperty', 'Classification of the contrast of coatings. See more in Guidelines for Soil Description issued by the FAO: table 65') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('coatingFormProperty', 'CoatingForm', 'http://w3id.org/glosis/model/layerhorizon/coatingFormProperty', 'Classification of the form of coatings. See more in Guidelines for Soil Description issued by the FAO: table 67') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('coatingLocationProperty', 'CoatingLocation', 'http://w3id.org/glosis/model/layerhorizon/coatingLocationProperty', 'Classification of the location of coatings and clay accumulation. See more in Guidelines for Soil Description issued by the FAO: table 68') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('coatingNatureProperty', 'CoatingNature', 'http://w3id.org/glosis/model/layerhorizon/coatingNatureProperty', 'Classification of the nature of coatings. See more in Guidelines for Soil Description issued by the FAO: table 66') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('consistenceDryProperty', 'ConsistenceDry', 'http://w3id.org/glosis/model/layerhorizon/consistenceDryProperty', 'The consistence when dry is determined by breaking an air-dried mass of soil between thumb and forefinger or in the hand. See more in the guidelines for Soil Description issued by the FAO: table 53') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('consistenceMoistProperty', 'ConsistenceMoist', 'http://w3id.org/glosis/model/layerhorizon/consistenceMoistProperty', 'Guidelines for Soil Description issued by the FAO: table 54;Consistence when moist is determined by attempting to crush a mass of moist or slightly moist soil material. See more in Guidelines for Soil Description issued by the FAO: table 54') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('fragmentsClassProperty', 'FragmentsClass', 'http://w3id.org/glosis/model/layerhorizon/fragmentsClassProperty', 'Horizon properties encountered in a global data compilation programme. See more in ISRIC Report 2019/01: Tier 1 and Tier 2 data in the context of the federated Global Soil Information System. Appendix 3') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('gypsumContentProperty', 'GypsumContent', 'http://w3id.org/glosis/model/layerhorizon/gypsumContentProperty', 'Where more readily soluble salts are absent, gypsum can be estimated in the field by measurements of electrical conductivity. More in the guidelines for Soil Description issued by the FAO: table 40') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('gypsumFormsProperty', 'GypsumForms', 'http://w3id.org/glosis/model/layerhorizon/gypsumFormsProperty', 'The forms of secondary gypsum in soils are diverse and are considered to be informative for diagnostics of soil genesis. See more information in the Guidelines for Soil Description issued by the FAO: table 41') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('mineralConcColourProperty', 'MineralConcColour', 'http://w3id.org/glosis/model/layerhorizon/mineralConcColourProperty', 'The general colour names are usually sufficient to describe the colour of the nodules (similar to mottles) or of artefacts. See more in Guidelines for Soil Description issued by the FAO: table 78') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('mineralConcHardnessProperty', 'MineralConcHardness', 'http://w3id.org/glosis/model/layerhorizon/mineralConcHardnessProperty', 'Classification of the hardness of mineral concentrations. More in the Guidelines for Soil Description issued by the FAO: table 76') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('mineralConcKindProperty', 'MineralConcKind', 'http://w3id.org/glosis/model/layerhorizon/mineralConcKindProperty', 'Classification of the kinds of mineral concentrations. See more in guidelines for Soil Description issued by the FAO: table 74') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('mineralConcNatureProperty', 'MineralConcNature', 'http://w3id.org/glosis/model/layerhorizon/mineralConcNatureProperty', 'Mineral concentrations are described according to the composition or impregnating substance.See more in Guidelines for Soil Description issued by the FAO: 77') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('mineralConcShapeProperty', 'MineralConcShape', 'http://w3id.org/glosis/model/layerhorizon/mineralConcShapeProperty', 'Classification of the size and shape of mineral concentrations. See more in Guidelines for Soil Description issued by the FAO: table 75,2') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('mineralConcSizeeProperty', 'MineralConcSize', 'http://w3id.org/glosis/model/layerhorizon/mineralConcSizeProperty', 'Classification of mineral concentrations based on size. See more in Guidelines for Soil Description issued by the FAO: table 75,1') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('mineralConcVolumeProperty', 'MineralConcVolume', 'http://w3id.org/glosis/model/layerhorizon/mineralConcVolumeProperty', 'The mineral concentrations are described according to their abundance, kind, size, shape, hardness, nature and colour. See more onGuidelines for Soil Description issued by the FAO: table 73') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('mineralFragmentsProperty', 'MineralFragments', 'http://w3id.org/glosis/model/layerhorizon/mineralFragmentsProperty', 'Codes for primary mineral fragments. See more in Guidelines for Soil Description issued by the FAO: table 30') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('mottlesAbundanceProperty', 'MottlesAbundance', 'http://w3id.org/glosis/model/layerhorizon/mottlesAbundanceProperty', 'The abundance of mottles is described in terms of classes indicating the percentage of the exposed surface that the mottles occupy. See more in the Guidelines for Soil Description issued by the FAO: table 32') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('mottlesBoundaryClassificationProperty', 'MottlesBoundaryClassification', 'http://w3id.org/glosis/model/layerhorizon/mottlesBoundaryClassificationProperty', 'The boundary between mottle and matrix is described as the thickness of the zone within which the colour transition can be located without being in either the mottle or matrix. See more in guidelines for Soil Description issued by the FAO: table 35') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('mottlesContrastProperty', 'MottlesContrast', 'http://w3id.org/glosis/model/layerhorizon/mottlesContrastProperty', 'The colour contrast between mottles and soil matrix. See more in Guidelines for Soil Description issued by the FAO: table 34') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('mottlesSizeProperty', 'MottlesSize', 'http://w3id.org/glosis/model/layerhorizon/mottlesSizeProperty', 'The individual classes of the mottle nodules according to their diameter size. See more in the guidelines for Soil Description issued by the FAO: table 33') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('peatDecompostionProperty', 'PeatDecompostion', 'http://w3id.org/glosis/model/layerhorizon/peatDecompostionProperty', 'In most organic layers of rocks the determination of the texture class is done by estimating of the degree of decomposition and humification of the organic material.See more in Guidelines for Soil Description issued by the FAO: table 31') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('peatDrainageProperty', 'PeatDrainage', 'http://w3id.org/glosis/model/layerhorizon/peatDrainageProperty', 'Bulk density and volume of solids of organic soils may be estimated after the decomposition stage or the extent of peat drainage. More information is in the guidelines for Soil Description issued by the FAO: table 59,1') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('peatVolumeProperty', 'PeatVolume', 'http://w3id.org/glosis/model/layerhorizon/peatVolumeProperty', 'Field estimation of volume of solids and bulk density of peat soils. See more in Guidelines for Soil Description issued by the FAO: table 59,2') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('plasticityProperty', 'Plasticity', 'http://w3id.org/glosis/model/layerhorizon/plasticityProperty', 'Plasticity is the ability of soil material to change shape continuously under the influence of an applied stress and to retain the compressed shape on removal of stress. See more in Guidelines for Soil Description issued by the FAO: Guidelines for Soil Description issued by the FAO: table 56') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('poresAbundanceProperty', 'PoresAbundance', 'http://w3id.org/glosis/model/layerhorizon/poresAbundanceProperty', 'Classification of abundance of pores. See more in Guidelines for Soil Description issued by the FAO: table 63') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('poresSizeProperty', 'PoresSize', 'http://w3id.org/glosis/model/layerhorizon/poresSizeProperty', 'Voids include all empty spaces in the soil. They are related to the arrangement of the primary soil constituents, rooting patterns, burrowing of animals or any other soil-forming processes, such as cracking, translocation and leaching. See more in Guidelines for Soil Description issued by the FAO: table 62') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('porosityClassProperty', 'PorosityClass', 'http://w3id.org/glosis/model/layerhorizon/porosityClassProperty', 'The porosity is an indication of the total volume of voids discernible with a ×10 hand-lens measured by area and recorded as the percentage of the surface occupied by pores. See more in guidelines for Soil Description issued by the FAO: table 60') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('rootsAbundanceProperty', 'RootsAbundance', 'http://w3id.org/glosis/model/layerhorizon/rootsAbundanceProperty', 'classification of the abundance of roots.. See more in Guidelines for Soil Description issued by the FAO: table 80') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('saltContentProperty', 'SaltContent', 'http://w3id.org/glosis/model/layerhorizon/saltContentProperty', 'Classification of salt content of soil. See more in Guidelines for Soil Description issued by the FAO: table 42') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('sandyTextureProperty', 'SandyTexture', 'http://w3id.org/glosis/model/layerhorizon/sandyTextureProperty', 'Relation of constituents of fine earth by size, defining textural classes and sand subclasses. See more in Guidelines for Soil Description issued by the FAO: figure 4,3') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('stickinessProperty', 'Stickiness', 'http://w3id.org/glosis/model/layerhorizon/stickinessProperty', 'Stickiness is the quality of adhesion of the soil material to other objects determined by noting the adherence of soil material when it is pressed between thumb and finger. See more in the Guidelines for Soil Description issued by the FAO: table 55') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('structureGradeProperty', 'StructureGrade', 'http://w3id.org/glosis/model/layerhorizon/structureGradeProperty', 'Guidelines for Soil Description issued by the FAO: table 47; Classification of structure of pedal soil materials. See more in Guidelines for Soil Description issued by the FAO: table 47') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('structureSizeProperty', 'StructureSize', 'http://w3id.org/glosis/model/layerhorizon/structureSizeProperty', 'Size classes for soil structure types. See more in guidelines for Soil Description issued by the FAO: table 50') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('VoidsClassificationProperty', 'VoidsClassification', 'http://w3id.org/glosis/model/layerhorizon/voidsClassificationProperty', 'Voids include all empty spaces in the soil. They are related to the arrangement of the primary soil constituents, rooting patterns, burrowing of animals or any other soil-forming processes, such as cracking, translocation and leaching. See more in Guidelines for Soil Description issued by the FAO: table 61') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_desc (property_desc_id, property_name, uri, definition) VALUES ('voidsDiameterProperty', 'VoidsDiameter', 'http://w3id.org/glosis/model/layerhorizon/voidsDiameterProperty', 'Voids include all empty spaces in the soil. They are related to the arrangement of the primary soil constituents, rooting patterns, burrowing of animals or any other soil-forming processes, such as cracking, translocation and leaching. See more in Guidelines for Soil Description issued by the FAO: table 62') ON CONFLICT DO NOTHING;
